#nullable enable // autogenerated

using MVZ2.GameContent.Contraptions;
using MVZ2.GameContent.Effects;
using MVZ2.GameContent.Seeds;
using MVZ2Logic.Contents.Enemies;
using MVZ2Logic.Entities;
using MVZ2Logic.Level;
using PVZEngine;
using PVZEngine.Level;
using UnityEngine;

namespace MVZ2.GameContent.Stages
{
    public class HeavyWeaponStageBehaviour : StageBehaviour
    {
        public HeavyWeaponStageBehaviour(StageDefinition stageDef) : base(stageDef)
        {
        }
        public override void Start(LevelEngine level)
        {
            base.Start(level);
            level.SetSeedSlotCount(3);
            level.FillSeedPacks(new NamespaceID[3]
            {
                VanillaBlueprintID.heavyWeaponNuke,
                VanillaBlueprintID.heavyWeaponRapid,
                VanillaBlueprintID.heavyWeaponSpread,
            });
            level.SetPickaxeActive(false);
            level.SetStarshardActive(false);
            level.SetTriggerActive(false);

            level.Spawn(VanillaEffectID.minecartRail, new Vector3(level.GetEntityColumnX(0), 0, level.GetLaneZ(2)), null)?.Let(rail =>
            {
                level.Spawn(VanillaEffectID.minecartRideable, rail.Position, rail)?.Let(cart =>
                {
                    cart.SetParent(rail);
                    level.Spawn(VanillaContraptionID.snipenser, cart.Position, rail)?.Let(snipenser =>
                    {
                        snipenser.RideOn(cart);
                    });
                });
            });
        }
    }
}
